sql:
SELECT AVG(department_size) AS average_department_size
FROM departments
WHERE department_head IS NOT NULL AND department_size > 5;

SELECT 
    SUM(department_budget) / SUM(department_size) AS average_budget_per_employee
FROM departments;

external_knowledge:
- 'stands out as the most lavishly funded' refers to the department with the highest budget value;
- 'towers above the rest with a budget that surpasses the average' means the budget value is greater than the average budget value across all departments;
- The budget values are assumed to be in thousands, as the last two characters of the budget are removed before conversion to a numeric value.

- 'crown of the highest budget' refers to the department with the highest budget rank;
- 'king in a kingdom of finances' is a metaphor for the top-ranked department in budget;
- 'size of its treasury' refers to the department's budget amount.

sql:
SELECT COUNT(*) AS large_budget_departments
FROM departments
WHERE CAST(department_budget AS REAL) > 500000.0;

external_knowledge:
- 'Department size' refers to the number of employees in a department;
- 'Average department size' is calculated as the total number of departments divided by 2;
- 'Unique department heads' means each department head is counted only once.

- 'branches of a tree' refers to sub-departments or departments under a main department;
- 'main stem' refers to the main department or the department head;
- 'annual nourishments' refers to the annual budget allocated to the department;
- 'leaves of education' refers to the number of different education levels associated with the department.

- 'stands tall like a giant' refers to the department having the highest annual budget;
- 'largest treasure chest' refers to the highest department budget;
- 'exceeding the average height of the common folk' refers to having more employees than the average department size.

- "Branches" and "leaves" are metaphors for departments and employees, respectively;
- "Height of the branches" refers to the level of the department in the hierarchy;
- "Total number of leaves" refers to the cumulative count of employees in each department.

sql:
SELECT department_head
FROM departments
WHERE department_size = (
    SELECT MAX(department_size)
    FROM departments
);

external_knowledge:
- 'sizable workforce' refers to departments with more than 5 employees;
- 'generous budget' refers to departments with an annual budget over $400,000;
- 'level of education' refers to the different education levels associated with the department.

sql:
SELECT COUNT(department_id) 
FROM departments 
WHERE CAST(department_budget AS REAL) > 50000 AND department_size > (SELECT AVG(department_size) FROM departments);
